  1→use serde::{Deserialize, Serialize};
  2→
  3→/// A contact in the CRM system.
  4→///
  5→/// Contacts represent people or entities that interact with the system through
  6→/// any channel (Telegram, WhatsApp, Slack, etc.) or are imported from external
  7→/// sources. The `source` field records which channel or import path created
  8→/// the contact; a typed channel reference can be added in a later phase.
  9→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 10→pub struct Contact {
 11→    /// Unique identifier (UUID v4).
 12→    pub id: String,
 13→    /// Human-readable display name.
 14→    pub name: String,
 15→    /// Origin channel or import source (e.g. `"telegram"`, `"whatsapp"`, `"csv-import"`).
 16→    #[serde(default)]
 17→    pub source: Option<String>,
 18→    /// Identifier assigned by the external channel (e.g. Telegram user ID).
 19→    #[serde(default)]
 20→    pub external_id: Option<String>,
 21→    /// Arbitrary structured metadata stored as a JSON object.
 22→    #[serde(default)]
 23→    pub metadata: serde_json::Value,
 24→    /// Unix timestamp (milliseconds) when the contact was created.
 25→    pub created_at: u64,
 26→    /// Unix timestamp (milliseconds) when the contact was last updated.
 27→    pub updated_at: u64,
 28→}
 29→
 30→impl Contact {
 31→    /// Create a new contact with the given name and auto-generated UUID.
 32→    #[must_use]
 33→    pub fn new(name: impl Into<String>) -> Self {
 34→        let now = now_ms();
 35→        Self {
 36→            id: uuid::Uuid::new_v4().to_string(),
 37→            name: name.into(),
 38→            source: None,
 39→            external_id: None,
 40→            metadata: serde_json::Value::Object(serde_json::Map::new()),
 41→            created_at: now,
 42→            updated_at: now,
 43→        }
 44→    }
 45→
 46→    /// Create a new contact with explicit source and external ID.
 47→    #[must_use]
 48→    pub fn with_source(
 49→        name: impl Into<String>,
 50→        source: impl Into<String>,
 51→        external_id: impl Into<String>,
 52→    ) -> Self {
 53→        let mut c = Self::new(name);
 54→        c.source = Some(source.into());
 55→        c.external_id = Some(external_id.into());
 56→        c
 57→    }
 58→}
 59→
 60→fn now_ms() -> u64 {
 61→    use std::time::{SystemTime, UNIX_EPOCH};
 62→    SystemTime::now()
 63→        .duration_since(UNIX_EPOCH)
 64→        .unwrap_or_default()
 65→        .as_millis() as u64
 66→}
 67→
 68→#[cfg(test)]
 69→#[allow(clippy::unwrap_used, clippy::expect_used)]
 70→mod tests {
 71→    use super::*;
 72→
 73→    #[test]
 74→    fn new_contact_has_uuid() {
 75→        let c = Contact::new("Alice");
 76→        assert!(!c.id.is_empty());
 77→        assert_eq!(c.name, "Alice");
 78→        assert!(c.source.is_none());
