            .create_interaction(Interaction::new(&cid, InteractionKind::Call, None))
            .await
            .unwrap();

        let by_matter = store.list_interactions_by_matter(&mid).await.unwrap();
        assert_eq!(by_matter.len(), 1);
        assert_eq!(by_matter[0].id, i.id);
