        let iid = i.id.clone();
        store.create_interaction(i).await.unwrap();
        store.delete_interaction(&iid).await.unwrap();
        store.delete_interaction(&iid).await.unwrap();
        assert!(store
            .list_interactions_by_contact(&cid)
            .await
            .unwrap()
            .is_empty());
    }

