/// Clear all data from tables but keep the schema intact.
async fn clear_databases() -> anyhow::Result<()> {
    let (main_db, memory_db) = db_paths();

    // Clear main database
    if main_db.exists() {
        let db_url = format!("sqlite:{}?mode=rwc", main_db.display());
        let pool = sqlx::SqlitePool::connect(&db_url).await?;

        // Order matters due to foreign key constraints.
        // Delete from child tables first.
        let mut tables: Vec<&str> = vec![
            // CRM (interactions and channels depend on contacts; interactions depend on matters)
            #[cfg(feature = "crm")]
            "crm_interactions",
            #[cfg(feature = "crm")]
            "crm_contact_channels",
            #[cfg(feature = "crm")]
            "crm_matters",
            #[cfg(feature = "crm")]
            "crm_contacts",
            // Sessions/channels (depends on projects)
