            }
        }

        pool.close().await;
        println!("Main database cleared.");
    } else {
        println!("Main database not found: {}", main_db.display());
    }

    // Clear memory database
    if memory_db.exists() {
        let db_url = format!("sqlite:{}?mode=rwc", memory_db.display());
